UPDATE ROOM
   SET CAFE_ID = #{cafeId}
     , ROOM_NAME = #{themeName}
     , GENRE_ID = #{genre}
     , DURATION = #{duration}
     , DIFFICULTY = #{difficulty}
     , HORROR_GRADE = #{horror}
     , ACTIVITY_GRADE = #{activity}
     , MIN_PLAYERS = #{minPlayers}
     , MAX_PLAYERS = #{maxPlayers}
     , ROOM_DESC = #{description}
     , ROOM_IMG = #{imagePath}
     , PRICE = #{price}
     , IS_ADULT = #{adult}
 WHERE ROOM_ID = #{themeId}

mapper.select:
SELECT A.ROOM_ID AS themeId, A.ROOM_IMG AS imagePath, A.ROOM_NAME AS themeName , B.GENRE_NAME AS genre, A.DURATION AS duration, A.DIFFICULTY AS difficulty , A.HORROR_GRADE AS horror, A.MIN_PLAYERS AS minPlayers, A.MAX_PLAYERS AS maxPlayers , A.PRICE AS price, C.CAFE_NAME AS cafeName FROM ROOM A JOIN ROOM_GENRE B ON A.GENRE_ID = B.GENRE_ID JOIN CAFE C ON A.CAFE_ID = C.CAFE_ID
AND A.ROOM_ID < #{lastId}
ORDER BY A.ROOM_ID DESC FETCH FIRST 4 ROWS ONLY
